INSERT INTO scenario_groups (id, slug, category) VALUES
  ('00000000-0000-0000-0000-000000000007', 'office-school1', 'work')
INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0006-000000000001', 'en', 1, 'user', 'Good morning, this is Minh. I''m afraid I''m not feeling well today and won''t be able to come in.', 'Chào buổi sáng, tôi là Minh. Hôm nay tôi không được khỏe và không thể đến được.'),
  ('00000000-0000-0000-0006-000000000001', 'en', 2, 'partner', 'Oh, I''m sorry to hear that. What''s wrong?', 'Ôi, tôi tiếc khi nghe điều đó. Bạn bị sao vậy?'),
  ('00000000-0000-0000-0006-000000000001', 'en', 3, 'user', 'I came down with a fever and a bad headache overnight. I''ve barely slept.', 'Tôi bị sốt và đau đầu dữ dội qua đêm. Gần như không ngủ được.'),
  ('00000000-0000-0000-0006-000000000001', 'en', 4, 'partner', 'That sounds rough. Please take the day off and rest up.', 'Nghe có vẻ nặng. Hãy nghỉ và nghỉ ngơi đi.'),
  ('00000000-0000-0000-0006-000000000001', 'en', 5, 'user', 'Thank you. I''m sorry for the short notice. I have a couple of things to hand over.', 'Cảm ơn. Tôi xin lỗi vì báo gấp. Tôi có vài việc cần bàn giao.'),
  ('00000000-0000-0000-0006-000000000001', 'en', 6, 'partner', 'That''s fine. What do you need covered?', 'Không sao. Bạn cần ai lo việc gì?'),
  ('00000000-0000-0000-0006-000000000001', 'en', 7, 'user', 'I have the Miller report due this afternoon. Could I ask Jen to step in? I''ll email her the draft right away.', 'Tôi có báo cáo Miller phải nộp chiều nay. Nhờ Jen thay được không? Tôi sẽ gửi bản nháp cho cô ấy ngay.'),
  ('00000000-0000-0000-0006-000000000001', 'en', 8, 'partner', 'I''ll let Jen know. Anything else?', 'Tôi sẽ báo Jen. Còn gì nữa không?'),
  ('00000000-0000-0000-0006-000000000001', 'en', 9, 'user', 'That should be it. My other meetings aren''t until tomorrow, so they''ll be fine.', 'Chỉ vậy thôi. Các cuộc họp khác của tôi là ngày mai, không ảnh hưởng.'),
  ('00000000-0000-0000-0006-000000000001', 'en', 10, 'partner', 'All right. Any idea when you''ll be back?', 'Được rồi. Bạn có biết khi nào quay lại không?'),
  ('00000000-0000-0000-0006-000000000001', 'en', 11, 'user', 'Hopefully tomorrow. I''ll message you tonight to let you know.', 'Hy vọng ngày mai. Tôi sẽ nhắn tin tối nay để báo.'),
  ('00000000-0000-0000-0006-000000000001', 'en', 12, 'partner', 'Sounds good. Take care and feel better soon.', 'Được rồi. Chăm sóc bản thân và mau khỏi nhé.');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0006-000000000002', 'ja', 1, 'user', 'おはようございます。グエン・ミンです。申し訳ありませんが、本日体調が優れず、お休みをいただきたいのですが。', 'Chào buổi sáng. Tôi là Nguyen Minh. Xin lỗi nhưng hôm nay tôi không khỏe, muốn xin nghỉ.', 'おはようございます。グエン・ミンです。もうしわけありませんが、ほんじつたいちょうがすぐれず、おやすみをいただきたいのですが。', 'Ohayō gozaimasu. Guen Min desu. Mōshiwake arimasen ga, honjitsu taichō ga sugurenzu, o-yasumi wo itadakitai no desu ga.'),
  ('00000000-0000-0000-0006-000000000002', 'ja', 2, 'partner', 'それは大変でしたね。どうされましたか？', 'Vậy à, thật vất vả nhỉ. Bạn bị sao?', 'それはたいへんでしたね。どうされましたか？', 'Sore wa taihen deshita ne. Dō saremashita ka?'),
  ('00000000-0000-0000-0006-000000000002', 'ja', 3, 'user', '昨夜から発熱しておりまして、38度を超えています。頭痛もひどく、ほとんど眠れませんでした。', 'Từ tối qua tôi bị sốt, nhiệt độ trên 38 độ. Đau đầu nặng và hầu như không ngủ được.', 'ゆうべからはつねつしておりまして、さんじゅうはちどをこえています。ずつうもひどく、ほとんどねむれませんでした。', 'Yūbe kara hatsunetsu shite orimashite, sanjū-hachi-do wo koete imasu. Zutsū mo hidoku, hotondo nemuremasen deshita.'),
  ('00000000-0000-0000-0006-000000000002', 'ja', 4, 'partner', 'それはつらいですね。今日はゆっくり休んでください。', 'Vất vả quá nhỉ. Hôm nay nghỉ ngơi đi.', 'それはつらいですね。きょうはゆっくりやすんでください。', 'Sore wa tsurai desu ne. Kyō wa yukkuri yasunde kudasai.'),
  ('00000000-0000-0000-0006-000000000002', 'ja', 5, 'user', 'ありがとうございます。急なご連絡で申し訳ございません。引き継ぎが必要な件があります。', 'Cảm ơn. Xin lỗi vì báo gấp. Có việc cần bàn giao.', 'ありがとうございます。きゅうなごれんらくでもうしわけございません。ひきつぎがひつようなけんがあります。', 'Arigatō gozaimasu. Kyū na go-renraku de mōshiwake gozaimasen. Hikitsugi ga hitsuyō na ken ga arimasu.'),
  ('00000000-0000-0000-0006-000000000002', 'ja', 6, 'partner', 'わかりました。何をお願いすればいいですか？', 'Hiểu rồi. Cần nhờ ai lo việc gì?', 'わかりました。なにをおねがいすればいいですか？', 'Wakarimashita. Nani wo onegai sureba ii desu ka?'),
  ('00000000-0000-0000-0006-000000000002', 'ja', 7, 'user', '今日の午後にミラー社への報告書の締め切りがあります。田中さんにお願いできれば、今すぐ下書きをメールで送ります。', 'Chiều nay có hạn nộp báo cáo cho công ty Miller. Nếu nhờ được Tanaka-san thì tôi sẽ gửi bản nháp ngay.', 'きょうのごごにミラーしゃへのほうこくしょのしめきりがあります。たなかさんにおねがいできれば、いますぐしたがきをメールでおくります。', 'Kyō no gogo ni Mirā-sha e no hōkoku-sho no shimekiri ga arimasu. Tanaka-san ni onegai dekireba, ima sugu shitagaki wo mēru de okurimasu.'),
  ('00000000-0000-0000-0006-000000000002', 'ja', 8, 'partner', '田中さんに伝えておきます。他にありますか？', 'Tôi sẽ báo Tanaka-san. Còn gì nữa không?', 'たなかさんにつたえておきます。ほかにありますか？', 'Tanaka-san ni tsutaete okimasu. Hoka ni arimasu ka?'),
  ('00000000-0000-0000-0006-000000000002', 'ja', 9, 'user', 'それだけです。明日以降の会議は大丈夫ですので、ご安心ください。', 'Chỉ vậy thôi. Các cuộc họp từ ngày mai không ảnh hưởng, bạn yên tâm.', 'それだけです。あしたいこうのかいぎはだいじょうぶですので、ごあんしんください。', 'Sore dake desu. Ashita ikō no kaigi wa daijōbu desu node, go-anshin kudasai.'),
  ('00000000-0000-0000-0006-000000000002', 'ja', 10, 'partner', 'わかりました。明日は出社できそうですか？', 'Hiểu rồi. Ngày mai có thể đi làm được không?', 'わかりました。あしたはしゅっしゃできそうですか？', 'Wakarimashita. Ashita wa shussha dekisō desu ka?'),
  ('00000000-0000-0000-0006-000000000002', 'ja', 11, 'user', '今夜の体調次第ですが、できればと思っております。夜にメッセージをお送りします。', 'Tùy vào tình trạng tối nay, hy vọng được. Tôi sẽ nhắn tin tối nay.', 'こんやのたいちょうしだいですが、できればとおもっております。よるにメッセージをおおくりします。', 'Konya no taichō shidai desu ga, dekireba to omotte orimasu. Yoru ni messēji wo o-okuri shimasu.'),
  ('00000000-0000-0000-0006-000000000002', 'ja', 12, 'partner', 'わかりました。無理せずゆっくり休んでください。', 'Hiểu rồi. Đừng cố, nghỉ ngơi cho tốt.', 'わかりました。むりせずゆっくりやすんでください。', 'Wakarimashita. Muri sezu yukkuri yasunde kudasai.');
INSERT INTO scenario_groups (id, slug, category) VALUES
  ('00000000-0000-0000-0000-000000000008', 'office-school2', 'work')
INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0006-000000000003', 'en', 1, 'partner', 'Right, let''s move on to the last item — any new ideas for the Q3 campaign?', 'Được rồi, hãy chuyển sang mục cuối — ai có ý tưởng mới cho chiến dịch Q3 không?'),
  ('00000000-0000-0000-0006-000000000003', 'en', 2, 'user', 'Yes, I have a suggestion, if I may.', 'Có, tôi có một đề xuất, nếu được phép.'),
  ('00000000-0000-0000-0006-000000000003', 'en', 3, 'partner', 'Please, go ahead.', 'Mời bạn cứ nói.'),
  ('00000000-0000-0000-0006-000000000003', 'en', 4, 'user', 'I think we should try a short-video series on social media. Our data shows engagement is significantly higher on video posts.', 'Tôi nghĩ chúng ta nên thử một series video ngắn trên mạng xã hội. Dữ liệu cho thấy tương tác với bài video cao hơn đáng kể.'),
  ('00000000-0000-0000-0006-000000000003', 'en', 5, 'partner', 'Interesting. Can you give us a rough idea of the cost?', 'Thú vị đấy. Bạn có thể ước tính chi phí không?'),
  ('00000000-0000-0000-0006-000000000003', 'en', 6, 'user', 'I haven''t done a full breakdown yet, but I''d estimate around five thousand for a three-video pilot. I can get the exact figures to you by tomorrow.', 'Tôi chưa tính chi tiết, nhưng ước tính khoảng 5.000 đô cho 3 video thử nghiệm. Tôi có thể đưa con số chính xác vào ngày mai.'),
  ('00000000-0000-0000-0006-000000000003', 'en', 7, 'partner', 'That could work. Does anyone else have thoughts on this?', 'Có thể được. Còn ai có ý kiến gì không?'),
  ('00000000-0000-0000-0006-000000000003', 'en', 8, 'user', 'I''d also like to add that we could tie this in with the August product launch. That way, we''d maximize reach.', 'Tôi cũng muốn bổ sung rằng có thể kết hợp với đợt ra mắt sản phẩm tháng 8. Như vậy sẽ tối đa hoá độ phủ sóng.'),
  ('00000000-0000-0000-0006-000000000003', 'en', 9, 'partner', 'Good thinking. What would the timeline look like?', 'Suy nghĩ tốt đấy. Lịch trình sẽ như thế nào?'),
  ('00000000-0000-0000-0006-000000000003', 'en', 10, 'user', 'If we approve the concept this week, we could start production in mid-July and launch by the first of August.', 'Nếu phê duyệt ý tưởng tuần này, chúng ta có thể bắt đầu sản xuất giữa tháng 7 và ra mắt ngày 1 tháng 8.'),
  ('00000000-0000-0000-0006-000000000003', 'en', 11, 'partner', 'That''s tight but doable. Let''s put it to a vote. All in favour?', 'Gấp nhưng khả thi. Hãy biểu quyết. Ai đồng ý?'),
  ('00000000-0000-0000-0006-000000000003', 'en', 12, 'user', 'I''m in favour. And I''m happy to lead the project if that helps.', 'Tôi đồng ý. Và tôi sẵn sàng dẫn dắt dự án nếu cần.');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0006-000000000004', 'ja', 1, 'partner', 'では、最後の議題に移りましょう。第3四半期のキャンペーンについて、何かアイデアはありますか？', 'Được, hãy chuyển sang chủ đề cuối. Ai có ý tưởng gì cho chiến dịch quý 3 không?', 'では、さいごのぎだいにうつりましょう。だいさんしはんきのキャンペーンについて、なにかアイデアはありますか？', 'Dewa, saigo no gidai ni utsurimashō. Dai-san shihan-ki no kyampēn ni tsuite, nanika aidea wa arimasu ka?'),
  ('00000000-0000-0000-0006-000000000004', 'ja', 2, 'user', 'はい、よろしければ一つご提案してもよいでしょうか。', 'Vâng, nếu được phép tôi muốn đề xuất một ý.', 'はい、よろしければひとつごていあんしてもよいでしょうか。', 'Hai, yoroshikereba hitotsu go-teian shite mo yoi deshō ka.'),
  ('00000000-0000-0000-0006-000000000004', 'ja', 3, 'partner', 'もちろんです。どうぞ。', 'Tất nhiên. Mời bạn.', 'もちろんです。どうぞ。', 'Mochiron desu. Dōzo.'),
  ('00000000-0000-0000-0006-000000000004', 'ja', 4, 'user', 'SNSで短い動画シリーズを展開することを提案したいと思います。データによると、動画投稿のエンゲージメントが大幅に高いことがわかっています。', 'Tôi muốn đề xuất triển khai series video ngắn trên mạng xã hội. Dữ liệu cho thấy tương tác với video cao hơn đáng kể.', 'SNSでみじかいどうがシリーズをてんかいすることをていあんしたいとおもいます。データによると、どうがとうこうのエンゲージメントがおおはばにたかいことがわかっています。', 'SNS de mijikai dōga shirīzu wo tenkai suru koto wo teian shitai to omoimasu. Dēta ni yoru to, dōga tōkō no engējiimento ga ōhaba ni takai koto ga wakatte imasu.'),
  ('00000000-0000-0000-0006-000000000004', 'ja', 5, 'partner', '面白い提案ですね。コスト感はいかがでしょうか？', 'Đề xuất thú vị. Chi phí dự kiến thế nào?', 'おもしろいていあんですね。コストかんはいかがでしょうか？', 'Omoshiroi teian desu ne. Kosuto-kan wa ikaga deshō ka?'),
  ('00000000-0000-0000-0006-000000000004', 'ja', 6, 'user', 'まだ詳しい見積もりは出していませんが、3本のパイロット動画で約50万円を見込んでいます。明日中に正確な数字をお出しできます。', 'Chưa tính chi tiết, nhưng dự kiến khoảng 500.000 yên cho 3 video thử nghiệm. Tôi có thể đưa con số chính xác vào ngày mai.', 'まだくわしいみつもりはだしていませんが、さんぼんのパイロットどうがでやくごじゅうまんえんをみこんでいます。あしたじゅうにせいかくなかずをおだしできます。', 'Mada kuwashii mitsumori wa dashite imasen ga, san-bon no pairotto dōga de yaku go-jū-man-en wo mikonde imasu. Ashita-jū ni seikaku na kazu wo o-dashi dekimasu.'),
  ('00000000-0000-0000-0006-000000000004', 'ja', 7, 'partner', '検討の余地がありますね。他にご意見はありますか？', 'Đáng cân nhắc đấy. Còn ai có ý kiến gì không?', 'けんとうのよちがありますね。ほかにごいけんはありますか？', 'Kentō no yochi ga arimasu ne. Hoka ni go-iken wa arimasu ka?'),
  ('00000000-0000-0000-0006-000000000004', 'ja', 8, 'user', '追加でお伝えすると、8月の製品ローンチに合わせることで、より大きなリーチが期待できます。', 'Thêm nữa, nếu kết hợp với đợt ra mắt sản phẩm tháng 8 thì có thể kỳ vọng độ phủ rộng hơn.', 'ついかでおつたえすると、はちがつのせいひんローンチにあわせることで、よりおおきなリーチがきたいできます。', 'Tsuika de o-tsutae suru to, hachi-gatsu no seihin rōnchi ni awaseru koto de, yori ōkina rīchi ga kitai dekimasu.'),
  ('00000000-0000-0000-0006-000000000004', 'ja', 9, 'partner', 'いい考えですね。スケジュールはどう見ていますか？', 'Ý hay đấy. Lịch trình bạn dự kiến thế nào?', 'いいかんがえですね。スケジュールはどうみていますか？', 'Ii kangae desu ne. Sukejūru wa dō mite imasu ka?'),
  ('00000000-0000-0000-0006-000000000004', 'ja', 10, 'user', '今週中に企画を承認いただければ、7月中旬から制作を開始し、8月1日のローンチに間に合わせることができます。', 'Nếu phê duyệt trong tuần này, chúng ta có thể bắt đầu sản xuất giữa tháng 7 và kịp ra mắt ngày 1 tháng 8.', 'こんしゅうじゅうにきかくをしょうにんいただければ、しちがつちゅうじゅんからせいさくをかいしし、はちがつついたちのローンチにまにあわせることができます。', 'Konshū-jū ni kikaku wo shōnin itadakereba, shichi-gatsu chūjun kara seisaku wo kaishi shi, hachi-gatsu tsuitachi no rōnchi ni maniawaseru koto ga dekimasu.'),
  ('00000000-0000-0000-0006-000000000004', 'ja', 11, 'partner', 'タイトですが実現可能ですね。採決を取りましょう。賛成の方は？', 'Gấp nhưng khả thi. Hãy biểu quyết. Ai đồng ý?', 'タイトですがじつげんかのうですね。さいけつをとりましょう。さんせいのかたは？', 'Taito desu ga jitsugen kanō desu ne. Saiketsu wo torimashō. Sansei no kata wa?'),
  ('00000000-0000-0000-0006-000000000004', 'ja', 12, 'user', '賛成です。もし必要であれば、プロジェクトのリードを担当します。', 'Tôi đồng ý. Nếu cần, tôi sẵn sàng dẫn dắt dự án.', 'さんせいです。もしひつようであれば、プロジェクトのリードをたんとうします。', 'Sansei desu. Moshi hitsuyō de areba, purojekuto no rīdo wo tantō shimasu.');
INSERT INTO scenario_groups (id, slug, category) VALUES
  ('00000000-0000-0000-0000-000000000009', 'office-school3', 'work')
INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0006-000000000005', 'en', 1, 'partner', 'Everyone, before we start — our new team member Minh is joining us today. Minh, would you like to say a few words?', 'Mọi người, trước khi bắt đầu — thành viên mới Minh gia nhập nhóm hôm nay. Minh, bạn có muốn nói vài lời không?'),
  ('00000000-0000-0000-0006-000000000005', 'en', 2, 'user', 'Sure! Hi everyone, my name is Minh Nguyen. I''m really happy to be joining the team.', 'Được thôi! Xin chào mọi người, tôi là Minh Nguyễn. Tôi rất vui được gia nhập nhóm.'),
  ('00000000-0000-0000-0006-000000000005', 'en', 3, 'partner', 'Could you tell us a bit about your background?', 'Bạn có thể kể một chút về kinh nghiệm của bạn không?'),
  ('00000000-0000-0000-0006-000000000005', 'en', 4, 'user', 'Of course. I''ve been working in marketing for about five years, mostly in digital campaigns and social media strategy.', 'Tất nhiên. Tôi đã làm marketing khoảng 5 năm, chủ yếu về chiến dịch kỹ thuật số và chiến lược mạng xã hội.'),
  ('00000000-0000-0000-0006-000000000005', 'en', 5, 'partner', 'Great. And what will you be focusing on here?', 'Tuyệt. Ở đây bạn sẽ tập trung vào mảng nào?'),
  ('00000000-0000-0000-0006-000000000005', 'en', 6, 'user', 'I''ll be joining the brand team, mainly working on campaign planning and content creation.', 'Tôi sẽ gia nhập đội thương hiệu, chủ yếu lập kế hoạch chiến dịch và tạo nội dung.'),
  ('00000000-0000-0000-0006-000000000005', 'en', 7, 'partner', 'Sounds like a great fit. Where were you before?', 'Nghe có vẻ rất phù hợp. Trước đây bạn làm ở đâu?'),
  ('00000000-0000-0000-0006-000000000005', 'en', 8, 'user', 'I was at a startup called CreativeFlow. It was a small team, so I wore a lot of hats — which I think made me quite adaptable.', 'Tôi làm ở startup tên CreativeFlow. Nhóm nhỏ nên tôi làm nhiều việc khác nhau — điều đó giúp tôi khá linh hoạt.'),
  ('00000000-0000-0000-0006-000000000005', 'en', 9, 'partner', 'We love versatile people! Is there anything outside work you''d like to share?', 'Chúng tôi thích người linh hoạt! Bạn có muốn chia sẻ gì ngoài công việc không?'),
  ('00000000-0000-0000-0006-000000000005', 'en', 10, 'user', 'Sure — I love hiking on weekends. And I''m learning Japanese, so if anyone speaks Japanese, I''d love to practice!', 'Có chứ — tôi thích đi leo núi vào cuối tuần. Và tôi đang học tiếng Nhật, nên nếu ai biết tiếng Nhật, tôi rất muốn luyện tập!'),
  ('00000000-0000-0000-0006-000000000005', 'en', 11, 'partner', 'Well, you''re in luck — two of our team members are from Japan. Welcome, Minh!', 'Bạn thật may mắn — hai thành viên trong nhóm là người Nhật. Chào mừng, Minh!'),
  ('00000000-0000-0000-0006-000000000005', 'en', 12, 'user', 'Thank you so much. I''m really looking forward to working with all of you!', 'Cảm ơn mọi người rất nhiều. Tôi rất mong được làm việc cùng tất cả!');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0006-000000000006', 'ja', 1, 'partner', 'みなさん、本日から新しいメンバーとして、グエン・ミンさんが加わります。ミンさん、ひと言ご挨拶をお願いできますか？', 'Mọi người, hôm nay có thành viên mới Nguyen Minh gia nhập. Minh-san, bạn có thể nói vài lời không?', 'みなさん、ほんじつからあたらしいメンバーとして、グエン・ミンさんがくわわります。ミンさん、ひとことごあいさつをおねがいできますか？', 'Mina-san, honjitsu kara atarashii menbā to shite, Guen Min-san ga kuwawarimasu. Min-san, hito-koto go-aisatsu wo onegai dekimasu ka?'),
  ('00000000-0000-0000-0006-000000000006', 'ja', 2, 'user', 'はい、よろしくお願いします。グエン・ミンと申します。本日からどうぞよろしくお願いいたします。', 'Vâng, rất vui được gặp mọi người. Tôi là Nguyen Minh. Mong mọi người giúp đỡ.', 'はい、よろしくおねがいします。グエン・ミンともうします。ほんじつからどうぞよろしくおねがいいたします。', 'Hai, yoroshiku onegai shimasu. Guen Min to mōshimasu. Honjitsu kara dōzo yoroshiku onegai itashimasu.'),
  ('00000000-0000-0000-0006-000000000006', 'ja', 3, 'partner', 'これまでどんなお仕事をされていましたか？', 'Trước đây bạn đã làm công việc gì?', 'これまでどんなおしごとをされていましたか？', 'Koremade donna o-shigoto wo sarete imashita ka?'),
  ('00000000-0000-0000-0006-000000000006', 'ja', 4, 'user', 'マーケティングを約5年間担当してきました。主にデジタルキャンペーンとSNS戦略を担当していました。', 'Tôi đã làm marketing khoảng 5 năm. Chủ yếu phụ trách chiến dịch kỹ thuật số và chiến lược mạng xã hội.', 'マーケティングをやくごねんかんたんとうしてきました。おもにデジタルキャンペーンとSNSせんりゃくをたんとうしていました。', 'Māketingu wo yaku go-nen-kan tantō shite kimashita. Omoni dejitaru kyampēn to SNS senryaku wo tantō shite imashita.'),
  ('00000000-0000-0000-0006-000000000006', 'ja', 5, 'partner', 'そうですか。こちらでは何を担当されるのですか？', 'Vậy à. Ở đây bạn sẽ phụ trách mảng gì?', 'そうですか。こちらではなにをたんとうされるのですか？', 'Sō desu ka. Kochira de wa nani wo tantō sareru no desu ka?'),
  ('00000000-0000-0000-0006-000000000006', 'ja', 6, 'user', 'ブランドチームに配属され、主にキャンペーンの企画とコンテンツ制作を担当する予定です。', 'Tôi được phân công vào đội thương hiệu, chủ yếu lập kế hoạch chiến dịch và sản xuất nội dung.', 'ブランドチームにはいぞくされ、おもにキャンペーンのきかくとコンテンツせいさくをたんとうするよていです。', 'Burando chīmu ni haizoku sare, omoni kyampēn no kikaku to kontentsu seisaku wo tantō suru yotei desu.'),
  ('00000000-0000-0000-0006-000000000006', 'ja', 7, 'partner', 'ぴったりのご経験ですね。前職はどちらでしたか？', 'Kinh nghiệm thật phù hợp. Trước đây bạn làm ở đâu?', 'ぴったりのごけいけんですね。ぜんしょくはどちらでしたか？', 'Pittari no go-keiken desu ne. Zenshoku wa dochira deshita ka?'),
  ('00000000-0000-0000-0006-000000000006', 'ja', 8, 'user', '「クリエイティブフロー」というスタートアップにおりました。小さなチームだったので、さまざまな業務を経験でき、柔軟に対応できるようになりました。', 'Tôi làm ở startup tên ''CreativeFlow''. Nhóm nhỏ nên tôi trải qua nhiều loại công việc, nhờ đó linh hoạt hơn.', '「クリエイティブフロー」というスタートアップにおりました。ちいさなチームだったので、さまざまなぎょうむをけいけんでき、じゅうなんにたいおうできるようになりました。', '「Kurieitivu Furō」 to iu sutātoappu ni orimashita. Chiisana chīmu datta node, samazama na gyōmu wo keiken deki, jūnan ni taiō dekiru yō ni narimashita.'),
  ('00000000-0000-0000-0006-000000000006', 'ja', 9, 'partner', '頼もしいですね！お仕事以外で何か教えていただけることはありますか？', 'Đáng tin cậy nhỉ! Ngoài công việc bạn có muốn chia sẻ gì không?', 'たのもしいですね！おしごといがいでなにかおしえていただけることはありますか？', 'Tanomoshii desu ne! O-shigoto igai de nanika oshiete itadakeru koto wa arimasu ka?'),
  ('00000000-0000-0000-0006-000000000006', 'ja', 10, 'user', 'はい、週末はハイキングをよくします。それから日本語を勉強しているので、日本語が話せる方がいれば、ぜひ練習させてください！', 'Có, cuối tuần tôi hay đi leo núi. Và tôi đang học tiếng Nhật, nếu có ai biết tiếng Nhật, xin hãy cho tôi luyện tập!', 'はい、しゅうまつはハイキングをよくします。それからにほんごをべんきょうしているので、にほんごがはなせるかたがいれば、ぜひれんしゅうさせてください！', 'Hai, shūmatsu wa haikingu wo yoku shimasu. Sorekara nihongo wo benkyō shite iru node, nihongo ga hanaseru kata ga ireba, zehi renshū sasete kudasai!'),
  ('00000000-0000-0000-0006-000000000006', 'ja', 11, 'partner', '実は、チームに日本人メンバーが2人いますよ。ようこそ、ミンさん！', 'Thực ra trong nhóm có 2 người Nhật đấy. Chào mừng, Minh-san!', 'じつは、チームににほんじんメンバーがふたりいますよ。ようこそ、ミンさん！', 'Jitsu wa, chīmu ni nihonjin menbā ga futari imasu yo. Yōkoso, Min-san!'),
  ('00000000-0000-0000-0006-000000000006', 'ja', 12, 'user', 'ありがとうございます。皆さんと一緒にお仕事できるのを楽しみにしています！', 'Cảm ơn mọi người. Tôi rất mong được làm việc cùng tất cả!', 'ありがとうございます。みなさんといっしょにおしごとできるのをたのしみにしています！', 'Arigatō gozaimasu. Mina-san to issho ni o-shigoto dekiru no wo tanoshimi ni shite imasu!');
INSERT INTO scenario_groups (id, slug, category) VALUES
  ('00000000-0000-0000-0000-000000000010', 'office-school4', 'work')
INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0006-000000000007', 'en', 1, 'partner', '...so the revised deadline will be the fourteenth, which ties into the stakeholder review on the fifteenth. Any questions?', '...vì vậy hạn chót sửa đổi sẽ là ngày 14, liên kết với đợt review từ stakeholder ngày 15. Có câu hỏi gì không?'),
  ('00000000-0000-0000-0006-000000000007', 'en', 2, 'user', 'Sorry, could I just check — did you say the fourteenth?', 'Xin lỗi, cho tôi xác nhận — bạn nói ngày 14 phải không?'),
  ('00000000-0000-0000-0006-000000000007', 'en', 3, 'partner', 'That''s right — the fourteenth of July.', 'Đúng rồi — ngày 14 tháng 7.'),
  ('00000000-0000-0000-0006-000000000007', 'en', 4, 'user', 'Got it. And could you say that again about the stakeholder review? I didn''t quite follow.', 'Hiểu rồi. Và bạn có thể nói lại về đợt review từ stakeholder không? Tôi không bắt kịp.'),
  ('00000000-0000-0000-0006-000000000007', 'en', 5, 'partner', 'Sure. The stakeholder review is the day after — the fifteenth. Everyone needs to submit before midnight on the fourteenth.', 'Tất nhiên. Review từ stakeholder là ngày hôm sau — ngày 15. Mọi người cần nộp trước nửa đêm ngày 14.'),
  ('00000000-0000-0000-0006-000000000007', 'en', 6, 'user', 'Perfect. And you mentioned a revised budget figure — could you repeat that number?', 'Tuyệt. Và bạn có nhắc đến con số ngân sách sửa đổi — bạn có thể nhắc lại không?'),
  ('00000000-0000-0000-0006-000000000007', 'en', 7, 'partner', 'The budget has been revised to eighty-five thousand — up from seventy-five.', 'Ngân sách được sửa lên 85.000 — tăng từ 75.000.'),
  ('00000000-0000-0000-0006-000000000007', 'en', 8, 'user', 'Eighty-five thousand. Got it. I just wanted to make sure I have the right number in my notes.', 'Tám mươi lăm nghìn. Hiểu rồi. Tôi chỉ muốn chắc chắn ghi đúng số.'),
  ('00000000-0000-0000-0006-000000000007', 'en', 9, 'partner', 'No problem at all. Does anyone else need anything clarified?', 'Không vấn đề gì. Còn ai cần làm rõ điều gì không?'),
  ('00000000-0000-0000-0006-000000000007', 'en', 10, 'user', 'Actually, I didn''t catch who is responsible for the final sign-off. Could you clarify?', 'À, tôi không nghe rõ ai chịu trách nhiệm phê duyệt cuối. Bạn có thể làm rõ không?'),
  ('00000000-0000-0000-0006-000000000007', 'en', 11, 'partner', 'That''ll be Sarah — she''s the project lead. All final approvals go through her.', 'Đó là Sarah — cô ấy là trưởng dự án. Tất cả phê duyệt cuối đều qua cô ấy.'),
  ('00000000-0000-0000-0006-000000000007', 'en', 12, 'user', 'Great. Thanks for your patience — I think I have everything I need now.', 'Tuyệt. Cảm ơn sự kiên nhẫn của bạn — tôi nghĩ tôi đã có đủ thông tin rồi.');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0006-000000000008', 'ja', 1, 'partner', '…ということで、修正後の締め切りは14日になります。翌15日に関係者レビューがあります。ご質問はありますか？', '...vì vậy hạn chót sửa đổi là ngày 14. Ngày 15 có đợt review từ stakeholder. Có câu hỏi gì không?', 'ということで、しゅうせいごのしめきりはじゅうよっかになります。よくじゅうごにちにかんけいしゃレビューがあります。ごしつもんはありますか？', 'To iu koto de, shūsei-go no shimekiri wa jū-yokka ni narimasu. Yoku jū-go-nichi ni kankeisha rebyū ga arimasu. Go-shitsumon wa arimasu ka?'),
  ('00000000-0000-0000-0006-000000000008', 'ja', 2, 'user', 'あの、確認させていただけますか？14日とおっしゃいましたか？', 'Xin lỗi, cho tôi xác nhận — bạn nói ngày 14 đúng không?', 'あの、かくにんさせていただけますか？じゅうよっかとおっしゃいましたか？', 'Ano, kakunin sasete itadakemasu ka? Jū-yokka to osshaimashita ka?'),
  ('00000000-0000-0000-0006-000000000008', 'ja', 3, 'partner', 'はい、7月14日です。', 'Đúng, ngày 14 tháng 7.', 'はい、しちがつじゅうよっかです。', 'Hai, shichi-gatsu jū-yokka desu.'),
  ('00000000-0000-0000-0006-000000000008', 'ja', 4, 'user', 'ありがとうございます。関係者レビューについて、もう一度おっしゃっていただけますか？少し聞き取れなかったので。', 'Cảm ơn. Về đợt review từ stakeholder, bạn có thể nói lại không? Tôi không nghe rõ lắm.', 'ありがとうございます。かんけいしゃレビューについて、もういちどおっしゃっていただけますか？すこしききとれなかったので。', 'Arigatō gozaimasu. Kankeisha rebyū ni tsuite, mō ichi-do osshatte itadakemasu ka? Sukoshi kikitorenakatta node.'),
  ('00000000-0000-0000-0006-000000000008', 'ja', 5, 'partner', 'はい。関係者レビューは翌日の15日です。14日の深夜0時までに全員提出する必要があります。', 'Vâng. Review từ stakeholder là ngày 15 hôm sau. Mọi người phải nộp trước nửa đêm ngày 14.', 'はい。かんけいしゃレビューはよくじつのじゅうごにちです。じゅうよっかのしんやれいじまでにぜんいんていしゅつするひつようがあります。', 'Hai. Kankeisha rebyū wa yokujitsu no jū-go-nichi desu. Jū-yokka no shin''ya rei-ji made ni zenin teishutsu suru hitsuyō ga arimasu.'),
  ('00000000-0000-0000-0006-000000000008', 'ja', 6, 'user', 'わかりました。予算の修正金額についてもおっしゃっていましたが、もう一度お願いできますか？', 'Hiểu rồi. Bạn cũng có nhắc đến con số ngân sách sửa đổi, bạn có thể nhắc lại không?', 'わかりました。よさんのしゅうせいきんがくについてもおっしゃっていましたが、もういちどおねがいできますか？', 'Wakarimashita. Yosan no shūsei kingaku ni tsuite mo osshatte imashita ga, mō ichi-do onegai dekimasu ka?'),
  ('00000000-0000-0000-0006-000000000008', 'ja', 7, 'partner', 'もちろんです。予算は75,000ドルから85,000ドルに修正されました。', 'Tất nhiên. Ngân sách được sửa từ 75.000 lên 85.000 đô.', 'もちろんです。よさんはなんまんごせんドルからはちまんごせんドルにしゅうせいされました。', 'Mochiron desu. Yosan wa nana-man go-sen doru kara hachi-man go-sen doru ni shūsei saremashita.'),
  ('00000000-0000-0000-0006-000000000008', 'ja', 8, 'user', '85,000ドルですね。ノートに正確に記録したいので、確認させていただきました。', '85.000 đô. Tôi muốn ghi chính xác vào ghi chú nên xác nhận lại.', 'はちまんごせんドルですね。ノートにせいかくにきろくしたいので、かくにんさせていただきました。', 'Hachi-man go-sen doru desu ne. Nōto ni seikaku ni kiroku shitai node, kakunin sasete itadakimashita.'),
  ('00000000-0000-0000-0006-000000000008', 'ja', 9, 'partner', '全く問題ありません。他に確認が必要な方はいらっしゃいますか？', 'Không vấn đề gì. Còn ai cần làm rõ điều gì không?', 'まったくもんだいありません。ほかにかくにんがひつようなかたはいらっしゃいますか？', 'Mattaku mondai arimasen. Hoka ni kakunin ga hitsuyō na kata wa irasshaimasu ka?'),
  ('00000000-0000-0000-0006-000000000008', 'ja', 10, 'user', 'もう一点、最終承認を誰が担当するのか聞き取れませんでした。教えていただけますか？', 'Thêm một điểm nữa, tôi không nghe rõ ai chịu trách nhiệm phê duyệt cuối. Bạn có thể cho biết không?', 'もういってん、さいしゅうしょうにんをだれがたんとうするのかききとれませんでした。おしえていただけますか？', 'Mō ichi-ten, saishū shōnin wo dare ga tantō suru no ka kikitoremasen deshita. Oshiete itadakemasu ka?'),
  ('00000000-0000-0000-0006-000000000008', 'ja', 11, 'partner', 'サラが担当します。彼女がプロジェクトリードです。最終承認はすべて彼女を通してください。', 'Sarah phụ trách. Cô ấy là trưởng dự án. Tất cả phê duyệt cuối đều qua cô ấy.', 'サラがたんとうします。かのじょがプロジェクトリードです。さいしゅうしょうにんはすべてかのじょをとおしてください。', 'Sara ga tantō shimasu. Kanojo ga purojekuto rīdo desu. Saishū shōnin wa subete kanojo wo tōshite kudasai.'),
  ('00000000-0000-0000-0006-000000000008', 'ja', 12, 'user', 'わかりました。丁寧に教えていただき、ありがとうございます。これで全部確認できました。', 'Hiểu rồi. Cảm ơn bạn đã giải thích tỉ mỉ. Tôi đã xác nhận được tất cả rồi.', 'わかりました。ていねいにおしえていただき、ありがとうございます。これでぜんぶかくにんできました。', 'Wakarimashita. Teinei ni oshiete itadaki, arigatō gozaimasu. Kore de zenbu kakunin dekimashita.');
